20	  it("should kill a live cell with four live neighbors (overpopulation)", () => {
21	    expect(nextGeneration(new Set(["0,0", "1,0", "-1,0", "0,1", "0,-1"]))).not.toContain("0,0");
22	  });
23	  it("should bring a dead cell to life when it has exactly three live neighbors (reproduction)", () => {
