1	function* neighborsOf(x: number, y: number): Generator<string> {
2	  for (let dx = -1; dx <= 1; dx++) {
3	    for (let dy = -1; dy <= 1; dy++) {
4	      if (dx === 0 && dy === 0) continue;
5	      yield `${x + dx},${y + dy}`;
6	    }
7	  }
8	}
9	
10	function isAliveNext(isCurrentlyAlive: boolean, liveNeighborCount: number): boolean {
11	  if (isCurrentlyAlive) return liveNeighborCount === 2 || liveNeighborCount === 3;
12	  return liveNeighborCount === 3;
13	}
14	
15	export function nextGeneration(livingCells: Set<string>): Set<string> {
16	  const neighborCounts = new Map<string, number>();
17	  for (const cell of livingCells) {
18	    const [x, y] = cell.split(",").map(Number);
19	    for (const neighbor of neighborsOf(x, y)) {
20	      neighborCounts.set(neighbor, (neighborCounts.get(neighbor) ?? 0) + 1);
21	    }
22	  }
23	  const nextGen = new Set<string>();
24	  for (const [cell, count] of neighborCounts) {
25	    if (isAliveNext(livingCells.has(cell), count)) nextGen.add(cell);
26	  }
27	  return nextGen;
28	}
